// ---------------------------
// Helpers
// ---------------------------
function scoreQuestion0to5(qid, answerId) {
  const map = SCORE_0_TO_5[qid];
  if (!map) return 0;
  const s = map[answerId];
  return typeof s === "number" ? s : 0;
}

function to0to10(score0to5) {
  return (score0to5 / 5) * 10;
}

function clamp0to10(v) {
  return Math.max(0, Math.min(10, v));
}

// ---------------------------
// 4) Compute pillar scores
// ---------------------------
const pillarTotals = Object.fromEntries(PILLARS.map(p => [p, 0]));
const pillarWeights = Object.fromEntries(PILLARS.map(p => [p, 0]));

const expectedQids = Object.keys(QUESTION_WEIGHTS);
const missingQuestions = [];

for (const qid of expectedQids) {
  const ans = raw[qid];
  if (!ans) missingQuestions.push(qid);

  const s0to5 = scoreQuestion0to5(qid, ans);
  const s0to10 = to0to10(s0to5);

  const weights = QUESTION_WEIGHTS[qid];
  for (const [pillar, w] of Object.entries(weights)) {
    pillarTotals[pillar] += s0to10 * w;
    pillarWeights[pillar] += w;
  }
}

const pillars = {};
for (const pillar of PILLARS) {
  const denom = pillarWeights[pillar] || 0;
  const rawScore = denom ? pillarTotals[pillar] / denom : 0;
  pillars[pillar] = clamp0to10(Math.round(rawScore * 10) / 10);
}

// Radar = same 5 pillars
const radar = { ...pillars };

// ---------------------------
// 5) Overall score (average of pillars, weighted by pillar importance)
// ---------------------------
const PILLAR_IMPORTANCE = {
  leadEngagementSpeed: 0.22,
  appointmentReliabilityConversion: 0.22,
  operationalFocusTimeEfficiency: 0.22,
  systemsAutomationMaturity: 0.22,
  revenueProtectionLeakageControl: 0.12
};

let overallNumerator = 0;
let overallDenom = 0;
for (const p of PILLARS) {
  const w = PILLAR_IMPORTANCE[p] || 0;
  overallNumerator += (pillars[p] || 0) * w;
  overallDenom += w;
}
const overallScore10 = overallDenom ? overallNumerator / overallDenom : 0;
const overallScore10Rounded = clamp0to10(Math.round(overallScore10 * 10) / 10);
const overallPercent = Math.round((overallScore10Rounded / 10) * 100);

// Bands (0–10)
function bandFor(score10) {
  if (score10 < 5.0) return "Critical";
  if (score10 < 7.0) return "Action Required";
  if (score10 < 9.0) return "Average";
  return "Optimised";
}
const maturityBand = bandFor(overallScore10Rounded);

// ---------------------------
// 6) Debug/QA (optional)
// ---------------------------
const qa = {
  missingQuestions,
  expectedQids
};

// ---------------------------
// 7) Informative-only answers (Q13–Q16)  // CHANGED: removed q15SolutionType
// ---------------------------
const informative = {
  q13DesiredOutcome: (() => {
    const v = raw["q13_desired_outcome"];
    if (Array.isArray(v)) return v;
    if (typeof v === "string" && v) return [v];
    return null;
  })(),
  q14AiBarriers: (() => {
    const v = raw["q14_ai_barriers"];
    if (Array.isArray(v)) return v;
    if (typeof v === "string" && v) return [v];
    return null;
  })(),
  // CHANGED: q15SolutionType REMOVED (q15_solution_type deleted – covered by q14_ai_barriers)
  q16AdditionalNotes: ($json.freeText && $json.freeText["q16_additional_notes"]) || null
};

// ---------------------------
// 8) Return
// ---------------------------
return [
  {
    json: {
      ...$json,
      scoring: {
        radar,
        pillars,
        overall: {
          score10: overallScore10Rounded,
          percent: overallPercent,
          maturityBand
        },
        informative,
        qa
      }
    }
  }
];

/**
 * Banding + Qualitative Copy Mapping (One Node) — with Traffic Light Colours
 *
 * Expects:
 *   $json.scoring.pillars = {
 *     leadEngagementSpeed: 0-10,
 *     appointmentReliabilityConversion: 0-10,
 *     operationalFocusTimeEfficiency: 0-10,
 *     systemsAutomationMaturity: 0-10,
 *     revenueProtectionLeakageControl: 0-10
 *   }
 *
 * Produces:
 *   $json.banding = { bandsMeta, overallBand }
 *   $json.pillarInsights = {
 *     [pillarKey]: { score, bandKey, bandLabel, bandMeaning, title, body, bandRange, bandColor }
 *   }
 */

const pillars = $json?.scoring?.pillars || {};
const overall10 = $json?.scoring?.overall?.score10 ?? null;

// ---------------------------
// 1) Band definitions (LOCKED) + Traffic Light Colours
// ---------------------------
const BAND_META = {
  critical: {
    label: "Critical",
    range: "0.0–4.9",
    meaning: "Structural blockers are actively limiting revenue, efficiency, or scale.",
    color: "#C62828" // red
  },
  action_required: {
    label: "Action Required",
    range: "5.0–6.9",
    meaning: "Core foundations exist, but execution is inconsistent or fragile.",
    color: "#C62828" // red
  },
  average: {
    label: "Average",
    range: "7.0–8.9",
    meaning: "Strong operating shape with clear leverage points.",
    color: "#F9A825" // amber
  },
  optimised: {
    label: "Optimised",
    range: "9.0–10.0",
    meaning: "Systemic advantage.",
    color: "#1B5E20" // dark green
  }
};

function bandScore(score) {
  const s = typeof score === "number" ? score : 0;
  if (s >= 9.0) return "optimised";
  if (s >= 7.0) return "average";
  if (s >= 5.0) return "action_required";
  return "critical";
}

// ---------------------------
// 2) Display labels for pillars (for HTML)
// ---------------------------
const PILLAR_LABELS = {
  leadEngagementSpeed: "Lead Engagement & Efficacy",
  appointmentReliabilityConversion: "Appointment Reliability & Conversion",
  operationalFocusTimeEfficiency: "Operational Focus & Time Efficiency",
  systemsAutomationMaturity: "Systems & Automation Maturity",
  revenueProtectionLeakageControl: "Revenue Protection & Leakage Control"
};

// ---------------------------
// 3) Qualitative copy mapping
// NOTE: keys updated to match new band keys
// ---------------------------
const QUAL_COPY = {
