  },

  revenueProtectionLeakageControl: {
    critical: {
      title: "Revenue loss is largely unmanaged",
      body: "Opportunities are being lost across the funnel without clear visibility into where or why. This makes revenue unpredictable and limits the ability to address the underlying causes of leakage. It’s important to understand that we cannot manage what we do not measure. Simple, comprehensive key metric dashboards should be present to provide domain-specific diagnostics in real time before deleterious impact is inevitable."
    },
    action_required: {
      title: "Leakage is visible, but not fully controlled",
      body: "Some drop-off points are understood, but controls are inconsistent. Revenue protection relies on manual monitoring rather than systemic safeguards, leaving avoidable value on the table."
    },
