      body: "The business has good visibility into where opportunities are lost and takes steps to reduce avoidable drop-off. This improves conversion efficiency and protects revenue without increasing acquisition spend."
    },
    optimised: {
      title: "Revenue is structurally protected",
      body: "Systems and processes are designed to minimise leakage at each stage of the journey. Opportunities are captured, qualified, and progressed consistently, creating more predictable and resilient revenue outcomes."
    }
  }
};

// ---------------------------
// 4) Build pillarInsights output
// ---------------------------
const pillarInsights = {};

for (const [pillarKey, score] of Object.entries(pillars)) {
  if (!PILLAR_LABELS[pillarKey]) continue;

  const bandKey = bandScore(score);
  const meta = BAND_META[bandKey];

  const copyBucket = QUAL_COPY[pillarKey] || {};
  const copy = copyBucket[bandKey] || { title: "", body: "" };

  pillarInsights[pillarKey] = {
    pillarKey,
    pillarLabel: PILLAR_LABELS[pillarKey],
    score: typeof score === "number" ? Math.round(score * 10) / 10 : 0,

    bandKey,
    bandLabel: meta.label,
    bandMeaning: meta.meaning,
    bandRange: meta.range,

    bandColor: meta.color,

    title: copy.title,
    body: copy.body
  };
}

// ---------------------------
// 5) Overall band (based on overall score10 if present)
// ---------------------------
let overallBand = null;
if (typeof overall10 === "number") {
  const k = bandScore(overall10);
  overallBand = {
    score10: Math.round(overall10 * 10) / 10,
    bandKey: k,
    bandLabel: BAND_META[k].label,
    bandMeaning: BAND_META[k].meaning,
    bandRange: BAND_META[k].range,
    bandColor: BAND_META[k].color
  };
}

// ---------------------------
// 6) Return enriched JSON
// ---------------------------
return [
  {
    json: {
      ...$json,
      banding: {
        bandsMeta: BAND_META,
        overallBand
      },
      pillarInsights
    }
  }
];

// Resolve upstream data
const edit = $('Edit Fields').first().json;
const banding = $('banding / qual mapping').first().json;

const to = edit.email || edit.body?.contact?.email || "";
const firstNameRaw = edit.name || edit.body?.contact?.name || "there";
const firstName = String(firstNameRaw).trim().split(" ")[0] || "there";

const pdf = (($json.pdf_base64 || "") + "")
  .replace(/^data:application\/pdf;base64,/, "");

// Build TOP_3_FINDINGS from lowest pillar scores
const pillarLabels = {
  leadEngagementSpeed: "Lead Engagement & Efficacy",
  appointmentReliabilityConversion: "Appointment Reliability & Conversion",
  operationalFocusTimeEfficiency: "Operational Focus & Time Efficiency",
  systemsAutomationMaturity: "Systems & Automation Maturity",
  revenueProtectionLeakageControl: "Revenue Protection & Leakage Control",
};

const scores = banding?.scoring?.pillars || {};
const insights = banding?.pillarInsights || {};

const top3 = Object.entries(scores)
  .map(([key, score]) => {
    const numericScore = typeof score === "number" ? score : 0;
    const label = insights[key]?.pillarLabel || pillarLabels[key] || key;
    const bandLabel = insights[key]?.bandLabel || "";
    return {
      label,
      score: numericScore,
      bandLabel,
    };
  })
  .sort((a, b) => a.score - b.score)
  .slice(0, 3);

const top3FindingsHtml = top3.length
  ? `<ul>${top3
      .map(
        (f) =>
          `<li><strong>${f.label}</strong> — ${f.score.toFixed(1)}/10${f.bandLabel ? ` (${f.bandLabel})` : ""}</li>`
      )
      .join("")}</ul>`
  : "<p>We identified several operational constraints that may be impacting revenue.</p>";

const body = {
  from: "HumTech.ai <hello@humtech.ai>",
  to,
  bcc: ["hello@humtech.ai"],
  subject: "Your HumTech AI Diagnostic",
  html: `
    <p>Hi ${firstName},</p>

    <p>Here’s a copy of your <strong>HumTech AI Diagnostic</strong>.</p>

    <p>Your diagnostic flagged the following areas which may be adversely impacting revenue:</p>
