const raw = $json.rawAnswers || {};
const q = $json.qualification || $json.body?.qualification || {};
const contact = $json.contact || $json.body?.contact || {};

// Qualification from frontend answer IDs
const leadVolumeMid = { A: 30, B: 125, C: 350, D: 600, E: 125 };
const dealValueMid = { A: 300, B: 1250, C: 6000, D: 15000, E: 1250 };

const grossRevenueAnnualMid = {
  A: 60000000, // 50m+
  B: 30000000, // 10-50m
  C: 7500000,  // 5-10m
  D: 4000000,  // 3-5m
  E: 2000000,  // <3m
  F: null      // unknown
};

const grossMarginMid = {
  A: 0.90,
  B: 0.80,
  C: 0.60,
  D: 0.40,
  E: 0.25,
  F: null
};

// Fallbacks if qualification missing
const defaultLeadVolume = contact.revenueRange5to500m === "yes" ? 125 : 30;
const defaultDealValue = contact.revenueRange5to500m === "yes" ? 6000 : 1250;

const leadVolume = leadVolumeMid[q.leadVolume] ?? defaultLeadVolume;
const avgDealValue = dealValueMid[q.dealValue] ?? defaultDealValue;
const estimatedAnnualRevenue = grossRevenueAnnualMid[q.estimatedGrossRevenue] ?? null;
const estimatedGrossMargin = grossMarginMid[q.estimatedGrossMargin] ?? null;

// Stage rates from existing scored answers
const ghostRateMap = { A: 0.10, B: 0.20, C: 0.35, D: 0.30, E: 0.35 };
const showRateMap = { A: 0.30, B: 0.50, C: 0.70, D: 0.85, E: 0.70 };
const conversionRateMap = { A: 0.80, B: 0.60, C: 0.35, D: 0.50 };

const ghostRate = ghostRateMap[raw.q1_engagement_method] ?? 0.35;
const showRate = showRateMap[raw.q4_show_rate] ?? 0.70;
const conversionRate = conversionRateMap[raw.q12_current_situation] ?? 0.55;

const pipeline = leadVolume * avgDealValue;
const engagementLoss = pipeline * ghostRate;
const afterEngagement = pipeline - engagementLoss;

const attendanceLoss = afterEngagement * (1 - showRate);
const afterAttendance = afterEngagement - attendanceLoss;

const conversionLoss = afterAttendance * (1 - conversionRate);
const closedValue = afterAttendance - conversionLoss;

const totalLoss = engagementLoss + attendanceLoss + conversionLoss;
const captureRatePercent = pipeline > 0 ? (closedValue / pipeline) * 100 : 0;

const biggestLeakStage = [
  { stage: "engagement", value: engagementLoss },
  { stage: "attendance", value: attendanceLoss },
  { stage: "conversion", value: conversionLoss },
].sort((a, b) => b.value - a.value)[0]?.stage || "engagement";

const recommendedLeadProduct =
  biggestLeakStage === "engagement"
    ? "speed_to_lead"
    : biggestLeakStage === "attendance"
    ? "attendance_automation"
    : "conversion_followup";

// Extra commercial lens using gross margin question
const grossProfitPipeline = estimatedGrossMargin == null ? null : pipeline * estimatedGrossMargin;
const grossProfitAtRisk = estimatedGrossMargin == null ? null : totalLoss * estimatedGrossMargin;

return [
  {
    json: {
      ...$json,
      revenueWaterfall: {
        leadVolume,
        avgDealValue,
        estimatedAnnualRevenue,
        estimatedGrossMargin,
        pipeline: Math.round(pipeline),
        engagementLoss: Math.round(engagementLoss),
        attendanceLoss: Math.round(attendanceLoss),
        conversionLoss: Math.round(conversionLoss),
        closedValue: Math.round(closedValue),
        totalLoss: Math.round(totalLoss),
        captureRatePercent: Math.round(captureRatePercent * 10) / 10,
        biggestLeakStage,
        grossProfitPipeline: grossProfitPipeline == null ? null : Math.round(grossProfitPipeline),
        grossProfitAtRisk: grossProfitAtRisk == null ? null : Math.round(grossProfitAtRisk),
      },
      qualification: {
        ...q,
        estimated_monthly_pipeline: Math.round(pipeline),
        estimated_monthly_loss: Math.round(totalLoss),
        capture_rate_percent: Math.round(captureRatePercent),
        biggest_leak_stage: biggestLeakStage,
        recommended_lead_product: recommendedLeadProduct,
        decision_maker: true,
      },
    },
  },
];

// Build GHL Payload (Code node)

const edit = $('Edit Fields').first().json;
const scoring = $('Question Scoring / pillar weight').first().json;
const waterfall = $('Revenue Waterfall / Qualification').first().json;

const allAnswers = edit.answers || [];

// Split full name -> first / last (for GHL automations)
const fullName = (edit.name || '').trim();
const nameParts = fullName.split(/\s+/).filter(Boolean);
const firstName = nameParts[0] || '';
const lastName = nameParts.length > 1 ? nameParts.slice(1).join(' ') : '';

// Full human-readable lines (question + selected answer sentence)
const answerLines = allAnswers.map((a) => {
  const answerText = Array.isArray(a.answerText)
    ? a.answerText.join('; ')
    : (a.answerText || '');
  return `${a.questionText}: ${answerText}`;
});

const scoredLines = allAnswers
  .filter((a) => a.isScored)
  .map((a) => {
    const answerText = Array.isArray(a.answerText)
      ? a.answerText.join('; ')
      : (a.answerText || '');
    return `${a.questionText}: ${answerText}`;
  });

const infoLines = allAnswers
  .filter((a) => !a.isScored)
  .map((a) => {
    const answerText = Array.isArray(a.answerText)
      ? a.answerText.join('; ')
      : (a.answerText || '');
    return `${a.questionText}: ${answerText}`;
  });

const payload = {
  email: edit.email || '',
  companyName: edit.company || '',
  name: fullName,
  firstName,
  lastName,
  job_title: edit.job_title || '',
  mobile: edit.mobile || '',
  submission_id: edit.submission_id || '',
  customFields: {
    humtech_assessment_version: 'v2',
    humtech_assessment_source: edit.source || 'humtech-scorecard',
    humtech_submitted_at: edit.submitted_at || '',

    // Added for easier automation branching in GHL
    humtech_first_name: firstName,
    humtech_last_name: lastName,

    humtech_overall_score: scoring.scoring?.overall?.score10 || '',
    humtech_overall_band: scoring.scoring?.overall?.maturityBand || '',
    humtech_lead_engagement_score: scoring.scoring?.pillars?.leadEngagementSpeed || '',
    humtech_appointment_reliability_score: scoring.scoring?.pillars?.appointmentReliabilityConversion || '',
    humtech_operational_focus_score: scoring.scoring?.pillars?.operationalFocusTimeEfficiency || '',
    humtech_systems_maturity_score: scoring.scoring?.pillars?.systemsAutomationMaturity || '',
    humtech_revenue_protection_score: scoring.scoring?.pillars?.revenueProtectionLeakageControl || '',

    humtech_pipeline_estimate: waterfall.revenueWaterfall?.pipeline || '',
    humtech_monthly_loss_estimate: waterfall.revenueWaterfall?.totalLoss || '',
    humtech_capture_rate_percent: waterfall.revenueWaterfall?.captureRatePercent || '',
    humtech_biggest_leak_stage: waterfall.revenueWaterfall?.biggestLeakStage || '',
    humtech_estimated_closed_value: waterfall.revenueWaterfall?.closedValue || '',

    humtech_lead_volume_tier: waterfall.qualification?.leadVolume || '',
    humtech_deal_value_tier: waterfall.qualification?.dealValue || '',
    humtech_estimated_gross_revenue_tier: waterfall.qualification?.estimatedGrossRevenue || '',
    humtech_estimated_gross_margin_tier: waterfall.qualification?.estimatedGrossMargin || '',
    humtech_recommended_lead_product: waterfall.qualification?.recommended_lead_product || '',

    // Raw + full answers
    humtech_assessment_raw_json: JSON.stringify(edit.rawAnswers || {}),
    humtech_assessment_answers_json: JSON.stringify(allAnswers || []),

    // Human-readable answer text (what they actually selected)
    humtech_answers_readable: answerLines.join('\n'),
    humtech_scored_answers_readable: scoredLines.join('\n'),
    humtech_informative_answers_readable: infoLines.join('\n'),
  },
};

return [{ json: { ...$json, ghl_payload: payload } }];
